mapper.select:
SELECT id, name
FROM md_role r
         LEFT JOIN md_tenant_role mtr ON (r.id = mtr.role_id)
WHERE r.status = 1
  AND mtr.app_id = #{appId}
  AND mtr.tenant_id = #{tenantId}
  AND mtr.role_id = #{roleId}

SELECT mu.id as id, mu.nickname as nickname, mu.email as email ,IF(LENGTH(mu.phone) = 11,CONCAT(SUBSTRING(mu.phone, 1, 3), '****', SUBSTRING(mu.phone, 8, 4)), mu.phone) AS phone FROM md_user_tenant_role muor RIGHT JOIN md_user mu ON muor.user_id = mu.id WHERE muor.role_id = #{roleId}
AND (LOWER(mu.nickname) like (concat('%', #{nickname},'%')) OR UPPER(mu.nickname) like (concat('%',#{nickname},'%')))
GROUP BY mu.id ORDER BY mu.create_time DESC

SELECT mr.id as id , name as name
FROM md_role mr
LEFT JOIN `md_user_tenant_role` mtr ON mtr.role_id = mr.id
WHERE mtr.app_id = #{appId}
AND mtr.tenant_id = #{tenantId}
AND mtr.user_id = #{userId}
AND mr.status=1
